struct AuthTokens: Codable, Equatable {
    let accessToken: String
    let refreshToken: String
    let expiresAt: Date
}

final class AuthManager: ObservableObject {
    static let shared = AuthManager()

    @Published private(set) var tokens: AuthTokens?
    @Published var isAuthenticated: Bool = false

    private let key = "auth.tokens"
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()

    private init() {
        encoder.dateEncodingStrategy = .iso8601
        decoder.dateDecodingStrategy = .iso8601
        load()
    }

    func load() {
        if let data = try? KeychainStore.shared.get(key),
           let data,
           let t = try? decoder.decode(AuthTokens.self, from: data) {
            tokens = t
            isAuthenticated = Date() < t.expiresAt
        } else {
            tokens = nil
            isAuthenticated = false
        }
    }

    func save(_ tokens: AuthTokens) {
        self.tokens = tokens
        self.isAuthenticated = Date() < tokens.expiresAt
        if let data = try? encoder.encode(tokens) {
            try? KeychainStore.shared.set(data, for: key)
        }
    }

    func signOut() {
        tokens = nil
        isAuthenticated = false
        KeychainStore.shared.delete(key)
    }

    func accessToken() -> String? {
        guard let t = tokens else { return nil }
        return Date() < t.expiresAt ? t.accessToken : nil
    }
}

// MARK: - Secure API Client (TLS + HMAC signing)

struct APIError: Error, LocalizedError {
    let message: String
    var errorDescription: String? { message }
}

final class APIClient: NSObject {
    static let shared = APIClient()

    private let session: URLSession
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()

    private let hmacKeyKeychainKey = "api.hmacKey"

    override init() {
        encoder.dateEncodingStrategy = .iso8601
        decoder.dateDecodingStrategy = .iso8601

        let config = URLSessionConfiguration.ephemeral
        config.waitsForConnectivity = true
        config.timeoutIntervalForRequest = 20
        config.timeoutIntervalForResource = 30
        config.httpAdditionalHeaders = [
            "Accept": "application/json",
            "Content-Type": "application/json"
        ]
        self.session = URLSession(configuration: config, delegate: nil, delegateQueue: nil)
        super.init()
        ensureHMACKey()
    }

    private func ensureHMACKey() {
        if let data = try? KeychainStore.shared.get(hmacKeyKeychainKey), data != nil { return }
        let key = SymmetricKey(size: .bits256)
        let data = key.withUnsafeBytes { Data($0) }
        try? KeychainStore.shared.set(data, for: hmacKeyKeychainKey)
    }

    private func loadHMACKey() throws -> SymmetricKey {
        guard let data = try KeychainStore.shared.get(hmacKeyKeychainKey), let data else {
            throw APIError(message: "Missing HMAC key")
        }
        return SymmetricKey(data: data)
    }

    private func sign(method: String, path: String, timestamp: String, body: Data?) throws -> String {
        let key = try loadHMACKey()
        var payload = "\(method.uppercased())\n\(path)\n\(timestamp)\n"
        if let body, !body.isEmpty {
            payload += body.base64EncodedString()
        }
        let mac = HMAC<SHA256>.authenticationCode(for: Data(payload.utf8), using: key)
        return Data(mac).base64EncodedString()
    }

    private func makeRequest<T: Encodable>(
        path: String,
        method: String,
        body: T? = nil,
        requiresAuth: Bool = true
    ) throws -> URLRequest {
        let url = AppConfig.apiBaseURL.appendingPathComponent(path)
        var req = URLRequest(url: url)
        req.httpMethod = method

        let ts = ISO8601DateFormatter().string(from: Date())
        let bodyData: Data?
        if let body {
            bodyData = try encoder.encode(body)
            req.httpBody = bodyData
        } else {
            bodyData = nil
        }

        req.setValue(ts, forHTTPHeaderField: "X-Timestamp")
        let signature = try sign(method: method, path: "/\(path)", timestamp: ts, body: bodyData)
        req.setValue(signature, forHTTPHeaderField: "X-Signature")

        if requiresAuth, let token = AuthManager.shared.accessToken() {
            req.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        return req
    }

    private func decodeOrThrow<T: Decodable>(_ data: Data, _ response: URLResponse) throws -> T {
        guard let http = response as? HTTPURLResponse else {
            throw APIError(message: "Invalid response")
        }
        if (200..<300).contains(http.statusCode) {
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                throw APIError(message: "Decode error: \(error.localizedDescription)")
            }
        } else {
            let msg = String(data: data, encoding: .utf8) ?? "HTTP \(http.statusCode)"
            throw APIError(message: msg)
        }
    }

    func get<T: Decodable>(_ path: String, requiresAuth: Bool = true) async throws -> T {
        let req = try makeRequest(path: path, method: "GET", body: Optional<Int>.none, requiresAuth: requiresAuth)
        let (data, resp) = try await session.data(for: req)
        return try decodeOrThrow(data, resp)
    }

    func post<B: Encodable, T: Decodable>(_ path: String, body: B, requiresAuth: Bool = true) async throws -> T {
        let req = try makeRequest(path: path, method: "POST", body: body, requiresAuth: requiresAuth)
        let (data, resp) = try await session.data(for: req)
        return try decodeOrThrow(data, resp)
    }

    func delete<T: Decodable>(_ path: String, requiresAuth: Bool = true) async throws -> T {
        let req = try makeRequest(path: path, method: "DELETE", body: Optional<Int>.none, requiresAuth: requiresAuth)
        let (data, resp) = try await session.data(for: req)
        return try decodeOrThrow(data, resp)
    }
}

