// MARK: - Realtime Stream (WebSocket)

enum StreamEventType: String, Codable {
    case quote, order, fill, heartbeat
}

struct StreamEnvelope<T: Codable>: Codable {
    let type: StreamEventType
    let data: T
}

final class RealtimeStream: ObservableObject {
    static let shared = RealtimeStream()

    @Published private(set) var quotes: [String: Quote] = [:]
    @Published private(set) var lastConnectionState: String = "Disconnected"

    private var task: URLSessionWebSocketTask?
    private var pingTimer: Timer?
    private let decoder = JSONDecoder()
    private let encoder = JSONEncoder()

    private init() {
        decoder.dateDecodingStrategy = .iso8601
        encoder.dateEncodingStrategy = .iso8601
    }

    func connect() {
        guard task == nil else { return }
        guard let token = AuthManager.shared.accessToken() else {
            lastConnectionState = "Auth required"
            return
        }

        var req = URLRequest(url: AppConfig.wsBaseURL)
        req.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")

        let session = URLSession(configuration: .ephemeral)
        let t = session.webSocketTask(with: req)
        task = t
        lastConnectionState = "Connecting"
        t.resume()
        lastConnectionState = "Connected"
        startPing()
        receiveLoop()
    }

    func disconnect() {
        pingTimer?.invalidate()
        pingTimer = nil
        task?.cancel(with: .goingAway, reason: nil)
        task = nil
        lastConnectionState = "Disconnected"
    }

    private func startPing() {
        pingTimer?.invalidate()
        pingTimer = Timer.scheduledTimer(withTimeInterval: 15, repeats: true) { [weak self] _ in
            self?.task?.sendPing { _ in }
        }
    }

    func subscribe(symbols: [String]) {
        guard let task else { return }
        let msg = ["action": "subscribe", "symbols": symbols] as [String: Any]
        if let data = try? JSONSerialization.data(withJSONObject: msg),
           let text = String(data: data, encoding: .utf8) {
            task.send(.string(text)) { _ in }
        }
    }

    private func receiveLoop() {
        guard let task else { return }
        task.receive { [weak self] result in
            guard let self else { return }
            switch result {
            case .failure:
                self.lastConnectionState = "Disconnected"
                self.disconnect()
            case .success(let message):
                self.handle(message)
                self.receiveLoop()
            }
        }
    }

    private func handle(_ message: URLSessionWebSocketTask.Message) {
        let data: Data?
        switch message {
        case .data(let d): data = d
        case .string(let s): data = s.data(using: .utf8)
        @unknown default: data = nil
        }
        guard let data else { return }

        if let env = try? decoder.decode(StreamEnvelope<Quote>.self, from: data), env.type == .quote {
            DispatchQueue.main.async {
                self.quotes[env.data.symbol] = env.data
            }
            return
        }
    }
}

// MARK: - Trading Engine (Optimistic UI + Risk checks)

struct RiskLimits {
    var maxOrderNotional: Double = 50_000
    var maxOrderQuantity: Double = 10_000
    var allowShortSelling: Bool = false
}

final class TradingEngine: ObservableObject {
    static let shared = TradingEngine()

    @Published private(set) var portfolio: Portfolio = Portfolio(cash: 0, positions: [])
    @Published private(set) var orders: [OrderResponse] = []
    @Published var isLoading: Bool = false
    @Published var lastError: String?
    @Published var toast: String?

    var risk = RiskLimits()

    private var cancellables = Set<AnyCancellable>()

    private init() {
        RealtimeStream.shared.$quotes
            .receive(on: DispatchQueue.main)
            .sink { [weak self] quotes in
                guard let self else { return }
                var p = self.portfolio
                for i in p.positions.indices {
                    if let q = quotes[p.positions[i].symbol] {
                        p.positions[i].marketPrice = q.last
                    }
                }
                self.portfolio = p
            }
            .store(in: &cancellables)
    }

    @MainActor
    func refreshAll() async {
        isLoading = true
        defer { isLoading = false }
        do {
            async let p = TradingAPI.shared.fetchPortfolio()
            async let o = TradingAPI.shared.fetchOrders()
            portfolio = try await p
            orders = try await o
            lastError = nil
        } catch {
            lastError = error.localizedDescription
        }
    }

    func validate(order: OrderRequest, quote: Quote?) -> String? {
        if order.quantity <= 0 { return "Quantity must be greater than 0." }
        if order.quantity > risk.maxOrderQuantity { return "Order quantity exceeds limit." }

        let refPrice: Double
        if order.type == .limit {
            guard let lp = order.limitPrice, lp > 0 else { return "Enter a valid limit price." }
            refPrice = lp
        } else {
            refPrice = quote?.last ?? quote?.ask ?? quote?.bid ?? 0
            if refPrice <= 0 { return "No market price available." }
        }

        let notional = refPrice * order.quantity
        if notional > risk.maxOrderNotional { return "Order notional exceeds limit." }

        if order.side == .sell, !risk.allowShortSelling {
            let posQty = portfolio.positions.first(where: { $0.symbol == order.symbol })?.quantity ?? 0
            if order.quantity > posQty { return "Insufficient shares (short selling disabled)." }
        }

        return nil
    }

    @MainActor
    func placeOrder(symbol: String, side: OrderSide, type: OrderType, quantity: Double, limitPrice: Double?) async {
        lastError = nil
        let clientOrderId = UUID().uuidString
        let req = OrderRequest(symbol: symbol.uppercased(), side: side, type: type, quantity: quantity, limitPrice: limitPrice, clientOrderId: clientOrderId)
        let quote = RealtimeStream.shared.quotes[req.symbol]

        if let msg = validate(order: req, quote: quote) {
            lastError = msg
            return
        }

        isLoading = true
        defer { isLoading = false }

        do {
            let resp = try await TradingAPI.shared.placeOrder(req)
            orders.insert(resp, at: 0)
            toast = "Order \(resp.status.rawValue.capitalized): \(resp.side.rawValue.uppercased()) \(resp.quantity.clean) \(resp.symbol)"
            await refreshAll()
        } catch {
            lastError = error.localizedDescription
        }
    }

    @MainActor
    func cancel(orderId: String) async {
        isLoading = true
        defer { isLoading = false }
        do {
            let updated = try await TradingAPI.shared.cancelOrder(orderId: orderId)
            if let idx = orders.firstIndex(where: { $0.id == updated.id }) {
                orders[idx] = updated
            }
            toast = "Order canceled"
            await refreshAll()
        } catch {
            lastError = error.localizedDescription
        }
    }
}

// MARK: - Formatting

extension Double {
    var clean: String {
        if self == .infinity || self.isNaN { return "-" }
        let f = NumberFormatter()
        f.numberStyle = .decimal
        f.maximumFractionDigits = 6
        f.minimumFractionDigits = 0
        return f.string(from: NSNumber(value: self)) ?? "\(self)"
    }

    func money(_ currencyCode: String = "USD") -> String {
        if self == .infinity || self.isNaN { return "-" }
        let f = NumberFormatter()
        f.numberStyle = .currency
        f.currencyCode = currencyCode
        f.maximumFractionDigits = 2
        return f.string(from: NSNumber(value: self)) ?? "\(self)"
    }

    func pct() -> String {
        if self == .infinity || self.isNaN { return "-" }
        let f = NumberFormatter()
        f.numberStyle = .percent
        f.maximumFractionDigits = 2
        return f.string(from: NSNumber(value: self)) ?? "\(self)"
    }
}

