                }
                Button("Cancel", role: .cancel) {}
            } message: {
                Text(orderSummary)
            }
            .onAppear {
                symbol = symbol.uppercased()
                stream.subscribe(symbols: Array(Set(AppConfig.defaultWatchlist + [symbol])))
            }
            .onChange(of: symbol) { _, newValue in
                symbol = newValue.uppercased()
                stream.subscribe(symbols: Array(Set(AppConfig.defaultWatchlist + [symbol])))
            }
        }
    }

    private var parsedQuantity: Double { Double(quantityText.replacingOccurrences(of: ",", with: "")) ?? 0 }
    private var parsedLimitPrice: Double { Double(limitPriceText.replacingOccurrences(of: ",", with: "")) ?? 0 }

    private var orderSummary: String {
        let q = quote
        let px: Double = {
            if type == .limit { return parsedLimitPrice }
            return q?.last ?? q?.ask ?? q?.bid ?? 0
        }()
        let notional = px * parsedQuantity
        var lines: [String] = []
        lines.append("\(side.rawValue.uppercased()) \(parsedQuantity.clean) \(symbol.uppercased())")
        lines.append("Type: \(type.rawValue.capitalized)")
        if type == .limit { lines.append("Limit: \(px.money())") }
        else { lines.append("Est. Price: \(px.money())") }
        lines.append("Est. Notional: \(notional.money())")
        return lines.joined(separator: "\n")
    }
}

struct QuoteCard: View {
    @Binding var symbol: String
    let quote: Quote?

    var body: some View {
        VStack(spacing: 12) {
            HStack(spacing: 12) {
                TextField("Symbol", text: $symbol)
                    .textInputAutocapitalization(.characters)
                    .autocorrectionDisabled()
                    .font(.title2.weight(.semibold))
                    .padding(10)
                    .background(.thinMaterial)
                    .clipShape(RoundedRectangle(cornerRadius: 12))

                Spacer()

                VStack(alignment: .trailing, spacing: 2) {
                    Text(quote?.last.money() ?? "--")
                        .font(.title2.bold())
                    let ch = quote?.change ?? 0
                    let pct = quote?.changePct ?? 0
                    Text("\(ch >= 0 ? "+" : "")\(ch.clean) (\(pct.pct()))")
                        .font(.subheadline.weight(.semibold))
                        .foregroundStyle(ch >= 0 ? .green : .red)
                }
            }

            HStack {
                StatPill(title: "Bid", value: quote?.bid.money() ?? "--")
                StatPill(title: "Ask", value: quote?.ask.money() ?? "--")
                StatPill(title: "Spread", value: spreadText)
            }
        }
        .padding()
        .background(.ultraThinMaterial)
        .clipShape(RoundedRectangle(cornerRadius: 18))
    }

    private var spreadText: String {
        guard let q = quote else { return "--" }
        let s = max(0, q.ask - q.bid)
        return s.money()
    }
}

struct StatPill: View {
    let title: String
