struct PortfolioView: View {
    @EnvironmentObject var engine: TradingEngine
    @EnvironmentObject var stream: RealtimeStream

    var body: some View {
        NavigationStack {
            List {
                Section {
                    HStack {
                        VStack(alignment: .leading, spacing: 4) {
                            Text("Equity").font(.caption).foregroundStyle(.secondary)
                            Text(engine.portfolio.equity.money()).font(.title3.bold())
                        }
                        Spacer()
                        VStack(alignment: .trailing, spacing: 4) {
                            Text("Cash").font(.caption).foregroundStyle(.secondary)
                            Text(engine.portfolio.cash.money()).font(.title3.weight(.semibold))
                        }
                    }
                    HStack {
                        VStack(alignment: .leading, spacing: 4) {
                            Text("Unrealized P/L").font(.caption).foregroundStyle(.secondary)
                            let pnl = engine.portfolio.unrealizedPnL
                            Text(pnl.money())
                                .font(.headline.weight(.semibold))
                                .foregroundStyle(pnl >= 0 ? .green : .red)
                        }
                        Spacer()
                        Text(stream.lastConnectionState)
                            .font(.caption)
                            .foregroundStyle(.secondary)
                    }
                }

                Section("Positions") {
                    if engine.portfolio.positions.isEmpty {
                        Text("No positions").foregroundStyle(.secondary)
                    } else {
                        ForEach(engine.portfolio.positions.sorted(by: { $0.marketValue > $1.marketValue })) { p in
                            PositionRow(position: p)
                        }
                    }
                }
            }
            .navigationTitle("Portfolio")
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button {
                        Task { await engine.refreshAll() }
                    } label: {
                        if engine.isLoading { ProgressView() } else { Image(systemName: "arrow.clockwise") }
                    }
                }
            }
            .refreshable { await engine.refreshAll() }
        }
    }
}

