                    .foregroundStyle(pnl >= 0 ? .green : .red)
            }
        }
    }
}

struct OrdersView: View {
    @EnvironmentObject var engine: TradingEngine

    var body: some View {
        NavigationStack {
            List {
                if engine.orders.isEmpty {
                    Text("No orders").foregroundStyle(.secondary)
                } else {
                    ForEach(engine.orders) { o in
                        OrderRow(order: o) {
