}

struct OrderRow: View {
    let order: OrderResponse
    let onCancel: () -> Void

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack {
                Text("\(order.side.rawValue.uppercased()) \(order.symbol)")
                    .font(.headline)
                Spacer()
                Text(order.status.rawValue.capitalized)
                    .font(.caption.weight(.semibold))
                    .padding(.horizontal, 10)
                    .padding(.vertical, 6)
                    .background(statusColor.opacity(0.15))
                    .foregroundStyle(statusColor)
                    .clipShape(Capsule())
            }

            HStack {
                Text("Qty \(order.quantity.clean)")
                Text("Filled \(order.filledQuantity.clean)")
                Spacer()
                if let avg = order.avgFillPrice {
                    Text("Avg \(avg.money())")
                } else {
                    Text(order.type == .limit ? "Limit" : "Market")
                }
            }
            .font(.caption)
            .foregroundStyle(.secondary)

            if order.status == .pending || order.status == .partiallyFilled {
                Button(role: .destructive) {
                    onCancel()
                } label: {
                    Text("Cancel Order")
                }
            }
        }
        .padding(.vertical, 6)
    }

    private var statusColor: Color {
        switch order.status {
        case .pending: return .orange
        case .filled: return .green
        case .partiallyFilled: return .blue
        case .canceled: return .gray
        case .rejected: return .red
        }
    }
}

struct SettingsView: View {
    @EnvironmentObject var auth: AuthManager
    @EnvironmentObject var stream: RealtimeStream
    @EnvironmentObject var engine: TradingEngine

    var body: some View {
        NavigationStack {
            Form {
                Section("Connectivity") {
                    HStack {
                        Text("Stream")
                        Spacer()
                        Text(stream.lastConnectionState).foregroundStyle(.secondary)
                    }
                    Button(stream.lastConnectionState == "Connected" ? "Disconnect" : "Connect") {
                        if stream.lastConnectionState == "Connected" {
                            stream.disconnect()
                        } else {
                            stream.connect()
                            stream.subscribe(symbols: AppConfig.defaultWatchlist)
                        }
                    }
                }

                Section("Risk Controls") {
                    Stepper("Max Notional: \(engine.risk.maxOrderNotional.money())", value: $engine.risk.maxOrderNotional, in: 1_000...500_000, step: 1_000)
                    Stepper("Max Quantity: \(engine.risk.maxOrderQuantity.clean)", value: $engine.risk.maxOrderQuantity, in: 1...1_000_000, step: 100)
                    Toggle("Allow Short Selling", isOn: $engine.risk.allowShortSelling)
                }

                Section("Account") {
                    Button(role: .destructive) {
                        auth.signOut()
                        stream.disconnect()
                    } label: {
                        Text("Sign Out")
                    }
                }
            }
            .navigationTitle("Settings")
        }
    }
}

